#include <bits/stdc++.h>
using namespace std;
int n,m,w[10003],c[101];
int main(){
    cin>>n>>m;
    for(int i=1;i<=n;i++)cin>>w[i];
    for(int i=1;i<=m;i++)
        c[i]=w[i];
    for(int i=m+1;i<=n;i++){
        int pos=1;
        for(int j=2;j<=m;j++)
            if(c[j]<c[pos])
                pos=j;
        c[pos]+=w[i];
    }
    int ans=0;
    for(int i=1;i<=m;i++)
        ans=max(ans,c[i]);
    cout<<ans;
    return 0;
}
